external_knowledge:
- 'travelers': refers to the unique users identified by 'user_id';
- 'voyages': represent the model runs identified by 'run_id';
- 'digital seas': a metaphor for the data stored in the database tables.

sql:
SELECT projects.project_name, models.model_name
FROM projects
INNER JOIN models ON projects.project_id = models.project_id;

SELECT run_duration
FROM model_runs
WHERE run_id = 1;

SELECT model_id, MAX(run_date) AS last_run_date
FROM model_runs
GROUP BY model_id;

SELECT run_id, model_id, accuracy
FROM model_runs
WHERE accuracy > 0.8;

SELECT up.user_id, COUNT(up.project_id) AS project_count
FROM user_projects up
GROUP BY up.user_id;
